// Typical Spring layered structure
// Presentation layer
@RestController
@RequestMapping("/orders")
public class OrderController {
    private final OrderService service;
    @PostMapping
    public ResponseEntity<OrderDto> place(@RequestBody PlaceOrderRequest req) {
        return ResponseEntity.status(201).body(service.placeOrder(req));
    }
}

// Service layer — orchestrates, contains business logic
@Service
public class OrderService {
    private final OrderRepository repo;
    private final PaymentGateway payment;
    public OrderDto placeOrder(PlaceOrderRequest req) {
        Order order = Order.from(req);   // domain object
        payment.charge(order.total());  // infrastructure call
        repo.save(order);               // persistence
        return OrderDto.from(order);
    }
}

// Repository layer — data access only
@Repository
public interface OrderRepository extends JpaRepository<Order, Long> {
    List<Order> findByCustomerId(long customerId);
}

// Core: pure Java, no framework dependencies
public class PlaceOrderUseCase {  // inbound port implementation
    private final OrderPort orderPort;         // outbound port
    private final PaymentPort paymentPort;     // outbound port

    public Order execute(PlaceOrderCommand cmd) {
        Order order = Order.create(cmd.items());
        paymentPort.charge(order.total(), cmd.paymentMethod());
        return orderPort.save(order);
    }
}

// Outbound port (interface in the core)
public interface OrderPort {
    Order save(Order order);
    Optional<Order> findById(long id);
}

// Adapter (infrastructure layer) — implements the port
@Repository
public class JpaOrderAdapter implements OrderPort {
    private final JpaOrderRepository jpa;
    public Order save(Order order) { return jpa.save(order); }
    public Optional<Order> findById(long id) { return jpa.findById(id); }
}

// Test: swap JPA adapter with in-memory adapter
class InMemoryOrderAdapter implements OrderPort {
    private final Map<Long, Order> store = new HashMap<>();
    public Order save(Order o) { store.put(o.id(), o); return o; }
    public Optional<Order> findById(long id) { return Optional.ofNullable(store.get(id)); }
}

// Bounded contexts — each service owns its domain
// Order Service: manages order lifecycle
// Payment Service: manages payment state
// Inventory Service: manages stock levels

// Each has its OWN database — no shared schema
order-service    → orders_db (Postgres)
payment-service  → payments_db (Postgres)
inventory-service → inventory_db (MySQL)

// Synchronous (REST/gRPC) — use for queries needing immediate response
OrderController → GET /inventory/items/42/stock (HTTP)

// Asynchronous (events) — use for state changes
OrderService.place()  → publishes OrderPlaced event to Kafka
InventoryService      ← subscribes, reserves stock asynchronously
PaymentService        ← subscribes, initiates charge asynchronously

// Distributed monolith smell:
OrderService  →  PaymentService  →  InventoryService  →  ShippingService
// Four synchronous hops — if any service is slow/down, all fail
// All services deployed together despite separate repos = pointless complexity

// Choreography: OrderService publishes, others react
// OrderService
ordersRepository.save(order);
kafka.send("order.placed", new OrderPlacedEvent(order.id()));

// InventoryService (separate service, subscribes independently)
@KafkaListener(topics = "order.placed")
public void onOrderPlaced(OrderPlacedEvent event) {
    inventoryService.reserve(event.orderId());
    kafka.send("inventory.reserved", new InventoryReservedEvent(event.orderId()));
}

// Outbox pattern — atomic DB write + event publish
// Problem: what if the app crashes between DB write and Kafka send?
// Solution: write event to outbox table in same transaction
@Transactional
public void placeOrder(Order order) {
    orderRepo.save(order);
    outboxRepo.save(new OutboxEvent("order.placed", order.id())); // same transaction
    // A separate Outbox relay process reads and publishes to Kafka
}
// Guarantees: order saved ↔ event published (atomically)
